        /* â”€â”€ Helper: parse gviz JSON response â†’ 2D array â”€â”€ */
        function _parseGvizResp(resp) {
            if (resp.status === 'error') {
                var errMsg = (resp.errors && resp.errors[0]) ? resp.errors[0].detailed_message || resp.errors[0].message : 'Unknown error';
                throw new Error(errMsg);
            }
            var table = resp.table; var rows = [];
            var hdr = table.cols.map(function (c) { return c.label || ''; });
            var colTypes = table.cols.map(function (c) { return c.type || ''; });
            if (hdr.some(function (h) { return h; })) rows.push(hdr);
            (table.rows || []).forEach(function (r) {
                var row = (r.c || []).map(function (cell, idx) {
                    if (!cell || cell.v == null) return '';
                    // FIX: For numeric columns, ALWAYS use raw .v (not formatted .f with Indonesian thousands)
                    var ct = colTypes[idx];
                    if (ct === 'number' || typeof cell.v === 'number') return cell.v;
                    // For non-numeric, prefer formatted display if available (e.g. dates)
                    if (cell.f != null && cell.f !== '') return cell.f;
                    return cell.v;
                });
                rows.push(row);
            });
            return rows;
        }

        /* â”€â”€ Fetch via fetch() API (works when served over http/https) â”€â”€ */
        function _gsFetchViaFetch(sheetId, gid) {
            var url = 'https://docs.google.com/spreadsheets/d/' + sheetId + '/gviz/tq?tqx=out:json&gid=' + gid + '&_=' + Date.now();
            return fetch(url).then(function (r) {
                if (!r.ok) throw new Error('HTTP ' + r.status);
                return r.text();
            }).then(function (txt) {
                /* Response is wrapped: google.visualization.Query.setResponse({...}) */
                var m = txt.match(/setResponse\(([\s\S]+)\)\s*;?\s*$/);
                if (!m) m = txt.match(/^\s*\{[\s\S]+\}\s*$/);
                if (!m) throw new Error('Bad response format');
                var json = m[1] || m[0];
                var resp = JSON.parse(json);
                return _parseGvizResp(resp);
            });
        }

        /* â”€â”€ Fetch via JSONP <script> tag (works from file:// protocol) â”€â”€ */
        function _gsFetchViaJSONP(sheetId, gid) {
            return new Promise(function (resolve, reject) {
                var cbName = '_gsCb' + gid + '_' + Date.now() + '' + Math.random().toString(36).slice(2, 10);
                var timer = setTimeout(function () {
                    delete window[cbName]; reject(new Error('Timeout (15s) â€” cek koneksi'));
                }, 15000);
                window[cbName] = function (resp) {
                    clearTimeout(timer); delete window[cbName];
                    var sc = document.querySelector('script[data-gscb="' + cbName + '"]');
                    if (sc) sc.remove();
                    try { resolve(_parseGvizResp(resp)); } catch (e) { reject(e); }
                };
                var s = document.createElement('script');
                s.setAttribute('data-gscb', cbName);
                s.src = 'https://docs.google.com/spreadsheets/d/' + sheetId + '/gviz/tq?tqx=out:json;responseHandler:' + cbName + '&gid=' + gid + '&headers=1&_=' + Date.now();
                s.onerror = function () {
                    clearTimeout(timer); delete window[cbName];
                    var sc2 = document.querySelector('script[data-gscb="' + cbName + '"]');
                    if (sc2) sc2.remove();
                    reject(new Error('Script load gagal â€” pastikan Sheet di-share "Anyone with the link"'));
                };
                document.head.appendChild(s);
            });
        }

        /* â”€â”€ Smart fetcher: try fetch() first (http), fall back to JSONP (file://) â”€â”€ */
        function gsFetchSheet(gid) {
            return _gsFetchViaFetch(GS_ID, gid).catch(function (fetchErr) {
                console.log('[GSheets] fetch() failed (' + fetchErr.message + '), trying JSONP...');
                return _gsFetchViaJSONP(GS_ID, gid);
            });
        }

