        /* â”€â”€ Robust name normalization for matching â”€â”€ */
        function _normName(n) { return String(n || '').toLowerCase().trim().replace(/[\u00A0\u2000-\u200B\u202F\u205F\u3000]/g, ' ').replace(/\s+/g, ' '); }

        /* â”€â”€ Helper: detect column index by keyword in header row â”€â”€ */
        function _findCol(headers, keywords) {
            for (var i = 0; i < headers.length; i++) {
                var h = String(headers[i] || '').toLowerCase().replace(/[_\-\s]+/g, '');
                for (var k = 0; k < keywords.length; k++) { if (h.indexOf(keywords[k]) >= 0) return i; }
            }
            return -1;
        }
        function _pNSafe(v) { var n = pN(String(v || '').replace(/[%,\s]/g, '')); return n == null ? 0 : n; }

        /* â”€â”€ Parse BREAKDOWN POIN MC sheet â†’ lookup by MC name â”€â”€ */
        function _parseBkdMC(rows) {
            var lookup = {};
            if (!rows || rows.length < 2) return lookup;
            var hdr = rows[0] || [];
            var cName = _findCol(hdr, ['nama', 'name']);
            var cMem = _findCol(hdr, ['member', 'mem']);
            var cCoach = _findCol(hdr, ['coach']);
            var cPil = _findCol(hdr, ['pilates', 'pil']);
            var cCorp = _findCol(hdr, ['corp', 'corporate']);
            var cPot = _findCol(hdr, ['pot', 'potongan']);
            var cTotal = _findCol(hdr, ['total', 'grand']);
            /* Fallback: if no headers detected, try positional (No,Name,Club,Mem,Coach,Pil,Corp,Pot,Total) */
            if (cName < 0) cName = 1;
            if (cMem < 0 && hdr.length > 4) cMem = 3;
            if (cCoach < 0 && hdr.length > 5) cCoach = 4;
            if (cPil < 0 && hdr.length > 6) cPil = 5;
            if (cCorp < 0 && hdr.length > 7) cCorp = 6;
            if (cPot < 0 && hdr.length > 8) cPot = 7;
            if (cTotal < 0 && hdr.length > 9) cTotal = 8;

            for (var i = 1; i < rows.length; i++) {
                var r = rows[i];
                var name = String(r[cName] || '').trim();
                if (!name || name.length < 2) continue;
                lookup[_normName(name)] = {
                    mem: cMem >= 0 ? _pNSafe(r[cMem]) : 0,
                    coach: cCoach >= 0 ? _pNSafe(r[cCoach]) : 0,
                    pilates: cPil >= 0 ? _pNSafe(r[cPil]) : 0,
                    corp: cCorp >= 0 ? _pNSafe(r[cCorp]) : 0,
                    potongan: cPot >= 0 ? _pNSafe(r[cPot]) : 0,
                    total: cTotal >= 0 ? _pNSafe(r[cTotal]) : 0
                };
            }
            return lookup;
        }

        /* â”€â”€ Parse BREAKDOWN POIN PT sheet â†’ lookup by PT name â”€â”€ */
        function _parseBkdPT(rows) {
            var lookup = {};
            if (!rows || rows.length < 2) return lookup;
            var hdr = rows[0] || [];
            var cName = _findCol(hdr, ['nama', 'name']);
            var cClub = _findCol(hdr, ['club', 'klub']);
            /* Try to detect monthly columns: look for month names in headers */
            var months = ['jan', 'feb', 'mar', 'apr', 'mei', 'may', 'jun', 'jul', 'aug', 'agu', 'sep', 'oct', 'okt', 'nov', 'dec', 'des'];
            var monthCols = {};
            for (var h = 0; h < hdr.length; h++) {
                var hl = String(hdr[h] || '').toLowerCase().replace(/[_\-\s]+/g, '');
                for (var mi = 0; mi < months.length; mi++) {
                    if (hl.indexOf(months[mi]) >= 0) {
                        var mKey = months[mi].substring(0, 3);
                        if (mKey === 'mei' || mKey === 'may') mKey = 'may';
                        if (mKey === 'agu') mKey = 'aug';
                        if (mKey === 'okt') mKey = 'oct';
                        if (mKey === 'des') mKey = 'dec';
                        if (!monthCols[mKey]) monthCols[mKey] = [];
                        monthCols[mKey].push(h);
                        break;
                    }
                }
            }
            if (cName < 0) cName = 1;

            for (var i = 1; i < rows.length; i++) {
                var r = rows[i];
                var name = String(r[cName] || '').trim();
                if (!name || name.length < 2) continue;
                var entry = { club: cClub >= 0 ? String(r[cClub] || '').trim() : '', months: {} };
                Object.keys(monthCols).forEach(function (mk) {
                    var cols = monthCols[mk];
                    if (cols.length >= 2) { entry.months[mk] = { b: _pNSafe(r[cols[0]]), r: _pNSafe(r[cols[1]]) }; }
                    else if (cols.length === 1) { entry.months[mk] = { b: 0, r: _pNSafe(r[cols[0]]) }; }
                });
                lookup[_normName(name)] = entry;
            }
            return lookup;
        }

        /* â”€â”€ Parse DETAIL TRANSAKSI sheet â†’ lookup by MC name â”€â”€ */
        function _parseTx(rows) {
            var byMC = {};
            if (!rows || rows.length < 2) return byMC;
            var hdr = rows[0] || [];
            var cName = _findCol(hdr, ['nama', 'name', 'mc']);
            var cType = _findCol(hdr, ['tipe', 'type', 'kategori', 'category', 'cat']);
            var cDur = _findCol(hdr, ['durasi', 'duration', 'dur', 'bulan']);
            var cNJM = _findCol(hdr, ['njm', 'new']);
            var cRenewal = _findCol(hdr, ['renew']);
            var cBundle = _findCol(hdr, ['bund', 'bundle']);
            var cClub = _findCol(hdr, ['club', 'klub']);
            var cMonth = _findCol(hdr, ['bulan', 'month', 'periode', 'period']);
            if (cName < 0) cName = 1;

            for (var i = 1; i < rows.length; i++) {
                var r = rows[i];
                var name = _normName(r[cName]);
                if (!name) continue;
                if (!byMC[name]) byMC[name] = [];
                byMC[name].push({
                    type: cType >= 0 ? String(r[cType] || '').trim() : '',
                    dur: cDur >= 0 ? String(r[cDur] || '').trim() : '',
                    njm: cNJM >= 0 ? (_pNSafe(r[cNJM]) > 0 || /ya|yes|1|njm/i.test(String(r[cNJM] || ''))) : false,
                    renewal: cRenewal >= 0 ? (_pNSafe(r[cRenewal]) > 0 || /ya|yes|1|renew/i.test(String(r[cRenewal] || ''))) : false,
                    bundled: cBundle >= 0 ? (_pNSafe(r[cBundle]) > 0 || /ya|yes|1/i.test(String(r[cBundle] || ''))) : false,
                    club: cClub >= 0 ? String(r[cClub] || '').trim() : '',
                    month: cMonth >= 0 ? String(r[cMonth] || '').trim() : ''
                });
            }
            return byMC;
        }

        /* â”€â”€ Build package analysis from transactions â”€â”€ */
        function _buildPkgFromTx(txList) {
            var cats = {}, memDurs = {};
            (txList || []).forEach(function (tx) {
                var t = tx.type || 'Unknown';
                cats[t] = (cats[t] || 0) + 1;
                if (/mem/i.test(t) && tx.dur) {
                    var dk = tx.dur.replace(/[^\d]/g, '') + 'M';
                    if (!memDurs[dk]) memDurs[dk] = { total: 0, njm: 0, renewal: 0 };
                    memDurs[dk].total++;
                    if (tx.njm) memDurs[dk].njm++;
                    if (tx.renewal) memDurs[dk].renewal++;
                }
            });
            return { cats: cats, mem_durs: memDurs };
        }

        /* â•â•â•â• LIVE UPDATE MCPT IFRAME FROM ALL GOOGLE SHEETS TABS â•â•â•â• */
        var _mcptUpdateRetries = 0;
        function updateMCPTIframeFromSheet() {
            var frame = document.getElementById('mcptFrame');
            if (!frame || !mcptLoaded) {
                console.log('[MCPT Update] iframe not ready, mcptLoaded=' + mcptLoaded + ', retries=' + _mcptUpdateRetries);
                if (_mcptUpdateRetries < 10 && (_mcptAllSheets || _mcptSheetRows)) { _mcptUpdateRetries++; setTimeout(updateMCPTIframeFromSheet, 1500); }
                return;
            }
            if (!_mcptAllSheets && !_mcptSheetRows) { console.log('[MCPT Update] no sheet data cached'); return; }
            try {
                var w = frame.contentWindow;
                if (!w || !w.RAW || !w.RAW.mcList) {
                    console.log('[MCPT Update] iframe window not ready (RAW missing), retry ' + _mcptUpdateRetries);
                    if (_mcptUpdateRetries < 10) { _mcptUpdateRetries++; setTimeout(updateMCPTIframeFromSheet, 1500); }
                    return;
                }
                _mcptUpdateRetries = 0;

                var sheets = _mcptAllSheets || { rapor: _mcptSheetRows };
                var raporRows = sheets.rapor;
                if (!raporRows || raporRows.length < 3) return;

                /* Parse all tabs */
                var ws = XLSX.utils.aoa_to_sheet(raporRows);
                var sheetMC = parseMC(ws);
                var sheetPT = parsePT(ws);
                var bkdMC = _parseBkdMC(sheets.bkdMC);
                var bkdPT = _parseBkdPT(sheets.bkdPT);
                var txByMC = _parseTx(sheets.tx);
                console.log('[MCPT Update] parsed: MC=' + sheetMC.length + ', PT=' + sheetPT.length + ', bkdMC=' + Object.keys(bkdMC).length + ', bkdPT=' + Object.keys(bkdPT).length + ', tx=' + Object.keys(txByMC).length);
                console.log('[MCPT Update] iframe RAW: mcList=' + w.RAW.mcList.length + ', ptList=' + w.RAW.ptList.length);

                /* Detect current month name */
                var mNames = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
                var curMonth = mNames[new Date().getMonth()];

                /* â”€â”€ Build MC list â”€â”€ */
                if (sheetMC.length > 0) {
                    var rawLookup = {};
                    w.RAW.mcList.forEach(function (m) { rawLookup[_normName(m.name)] = m; });
                    var updatedMC = [];

                    sheetMC.forEach(function (sm) {
                        var key = _normName(sm.name);
                        var ex = rawLookup[key] || null;
                        var bkd = bkdMC[key] || {};
                        var txList = txByMC[key] || [];
                        var p = sm.poin || 0;
                        var tn = 0;
                        var jd = sm.joinDate || '';
                        if (jd) { try { tn = Math.max(0, Math.round((new Date() - new Date(jd)) / (30.44 * 864e5))); } catch (e) { } }

                        if (ex) {
                            ex._matched = true;
                            /* Update existing MC with fresh data */
                            if (sm.totalClosing != null) ex.total_closing = sm.totalClosing;
                            if (sm.closingShowedRate != null) ex.closing_pct = sm.closingShowedRate;
                            if (sm.leads != null) ex.leads = sm.leads;
                            if (sm.njm != null) ex.njm = sm.njm;
                            if (sm.closingLeadsRate != null) ex.clr = sm.closingLeadsRate;
                            if (sm.renewal != null) ex.renewal = sm.renewal;
                            if (sm.renewalRate != null) ex.renewal_pct = sm.renewalRate;
                            ex.tenure = tn;
                            /* Update poin */
                            if (p != null) {
                                var mk = Object.keys(ex).filter(function (k) { return /_poin$/.test(k) && ['avg_poin', 'mem_poin', 'coach_poin', 'pilates_poin', 'corp_poin'].indexOf(k) < 0; });
                                if (mk.length) ex[mk[mk.length - 1]] = p;
                                if (ex.monthly_poin && ex.monthly_poin.length) {
                                    ex.monthly_poin[ex.monthly_poin.length - 1] = p;
                                    var s = 0; ex.monthly_poin.forEach(function (v) { s += v; });
                                    ex.avg_poin = s / ex.monthly_poin.length;
                                    if (ex.monthly_poin.length >= 2) ex.mom_diff = p - ex.monthly_poin[ex.monthly_poin.length - 2];
                                }
                                ex.mar_zero = (p === 0);
                            }
                            /* Update breakdown from BREAKDOWN POIN MC */
                            if (bkd.mem != null) ex.mem_poin = bkd.mem;
                            if (bkd.coach != null) ex.coach_poin = bkd.coach;
                            if (bkd.pilates != null) ex.pilates_poin = bkd.pilates;
                            if (bkd.corp != null) ex.corp_poin = bkd.corp;
                            if (bkd.potongan != null) ex.potongan = bkd.potongan;
                            /* Update monthly_detail breakdown for current month */
                            if (ex.monthly_detail && (bkd.mem || bkd.coach || bkd.pilates)) {
                                var mdKey = Object.keys(ex.monthly_detail).pop();
                                if (mdKey && ex.monthly_detail[mdKey]) {
                                    if (!ex.monthly_detail[mdKey].breakdown) ex.monthly_detail[mdKey].breakdown = {};
                                    ex.monthly_detail[mdKey].breakdown.mem = bkd.mem || 0;
                                    ex.monthly_detail[mdKey].breakdown.coach = bkd.coach || 0;
                                    ex.monthly_detail[mdKey].breakdown.pilates = bkd.pilates || 0;
                                    ex.monthly_detail[mdKey].breakdown.corp = bkd.corp || 0;
                                    ex.monthly_detail[mdKey].breakdown.pot = bkd.potongan || 0;
                                }
                            }
                            /* Update packages from DETAIL TRANSAKSI */
                            if (txList.length > 0 && ex.monthly_detail) {
                                var mdKey2 = Object.keys(ex.monthly_detail).pop();
                                if (mdKey2 && ex.monthly_detail[mdKey2]) {
                                    ex.monthly_detail[mdKey2].packages = _buildPkgFromTx(txList);
                                }
                            }
                            updatedMC.push(ex);
                            delete rawLookup[key];
                        } else {
                            /* New MC â€” build from scratch */
                            var newMC = {
                                name: sm.name, club: sm.club || '', join_date: jd, tenure: tn,
                                mar_poin: p, feb_poin: 0, jan_poin: 0, avg_poin: p, mom_diff: 0,
                                njm: sm.njm || 0, total_closing: sm.totalClosing || 0, closing_pct: sm.closingShowedRate || 0,
                                clr: sm.closingLeadsRate || 0, leads: sm.leads || 0, renewal: sm.renewal || 0, renewal_pct: sm.renewalRate || 0,
                                insufficient: false, mar_zero: p === 0,
                                mem_poin: bkd.mem || p, coach_poin: bkd.coach || 0, pilates_poin: bkd.pilates || 0,
                                corp_poin: bkd.corp || 0, potongan: bkd.potongan || 0,
                                monthly_poin: [0, 0, p], monthly_detail: {},
                                status: '', rating: 0, rating_label: 'N/A', rank_club: 0, diagnoses: []
                            };
                            /* Build monthly_detail for current month */
                            var md = {
                                poin: p, closing_pct: sm.closingShowedRate || 0, njm: sm.njm || 0, leads: sm.leads || 0,
                                clr: sm.closingLeadsRate || 0, renewal_pct: sm.renewalRate || 0,
                                breakdown: { mem: bkd.mem || 0, coach: bkd.coach || 0, pilates: bkd.pilates || 0, corp: bkd.corp || 0, pot: bkd.potongan || 0 }
                            };
                            if (txList.length) md.packages = _buildPkgFromTx(txList);
                            else md.packages = { cats: {}, mem_durs: {} };
                            newMC.monthly_detail[curMonth] = md;
                            updatedMC.push(newMC);
                        }
                    });
                    w.RAW.mcList.length = 0;
                    updatedMC.forEach(function (m) { w.RAW.mcList.push(m); });
                    console.log('[MCPT Update] MC list replaced: ' + w.RAW.mcList.length + ' items (matched=' + updatedMC.filter(function (m) { return m._matched; }).length + ', new=' + updatedMC.filter(function (m) { return !m._matched; }).length + ')');
                } else {
                    console.log('[MCPT Update] WARNING: parseMC returned 0 results â€” rapor rows=' + raporRows.length + ', first row=' + JSON.stringify((raporRows[0] || []).slice(0, 5)));
                }

                /* â”€â”€ Build PT list â”€â”€ */
                if (sheetPT.length > 0) {
                    var ptRawLookup = {};
                    w.RAW.ptList.forEach(function (p) { ptRawLookup[_normName(p.name)] = p; });
                    var updatedPT = [];

                    sheetPT.forEach(function (sp) {
                        var key = _normName(sp.name);
                        var ex = ptRawLookup[key] || null;
                        var bkdP = bkdPT[key] || { months: {} };

                        if (ex) {
                            /* Update existing PT */
                            if (sp.mar) { if (sp.mar.r != null) ex.mar_reg = sp.mar.r; if (sp.mar.b != null) ex.mar_bund = sp.mar.b; }
                            if (sp.feb) { if (sp.feb.r != null) ex.feb_reg = sp.feb.r; if (sp.feb.b != null) ex.feb_bund = sp.feb.b; }
                            if (sp.jan) { if (sp.jan.r != null) ex.jan_reg = sp.jan.r; }
                            if (sp.avg && sp.avg.r != null) ex.avg_reg = sp.avg.r;
                            if (ex.mar_reg && ex.feb_reg) ex.mom_pct = ((ex.mar_reg - ex.feb_reg) / Math.max(1, ex.feb_reg) * 100);
                            if (ex.monthly_reg && ex.monthly_reg.length >= 3) {
                                ex.monthly_reg[0] = ex.jan_reg || 0; ex.monthly_reg[1] = ex.feb_reg || 0; ex.monthly_reg[2] = ex.mar_reg || 0;
                            }
                            /* Update from BKD PT sheet if available */
                            var bMonths = bkdP.months || {};
                            Object.keys(bMonths).forEach(function (mk) {
                                var bm = bMonths[mk];
                                if (mk === 'mar') { if (bm.r) ex.mar_reg = bm.r; if (bm.b) ex.mar_bund = bm.b; }
                                if (mk === 'feb') { if (bm.r) ex.feb_reg = bm.r; if (bm.b) ex.feb_bund = bm.b; }
                                if (mk === 'jan') { if (bm.r) ex.jan_reg = bm.r; }
                            });
                            updatedPT.push(ex);
                            delete ptRawLookup[key];
                        } else {
                            /* New PT */
                            var mr = sp.mar ? sp.mar.r || 0 : 0, fr = sp.feb ? sp.feb.r || 0 : 0, jr = sp.jan ? sp.jan.r || 0 : 0;
                            var mb = sp.mar ? sp.mar.b || 0 : 0, fb = sp.feb ? sp.feb.b || 0 : 0;
                            var ar = sp.avg ? sp.avg.r || 0 : 0;
                            updatedPT.push({
                                name: sp.name, club: sp.club || '', tenure: 0, join_date: '',
                                mar_reg: mr, feb_reg: fr, jan_reg: jr, mar_bund: mb, feb_bund: fb,
                                avg_reg: ar, mom_pct: fr ? (mr - fr) / Math.max(1, fr) * 100 : 0,
                                insufficient: false, monthly_reg: [jr, fr, mr], monthly_sessions: [],
                                status: '', rank_club: 0
                            });
                        }
                    });
                    w.RAW.ptList.length = 0;
                    updatedPT.forEach(function (p) { w.RAW.ptList.push(p); });
                    console.log('[MCPT Update] PT list replaced: ' + w.RAW.ptList.length + ' items');
                } else {
                    console.log('[MCPT Update] WARNING: parsePT returned 0 results');
                }

                /* â”€â”€ Rebuild clubSummary â”€â”€ */
                var clubMap = {};
                w.RAW.mcList.forEach(function (m) {
                    if (!clubMap[m.club]) clubMap[m.club] = { club: m.club, type: '', mc_count: 0, pt_count: 0, total_poin: 0 };
                    clubMap[m.club].mc_count++; clubMap[m.club].total_poin += (m.avg_poin || 0);
                });
                w.RAW.ptList.forEach(function (p) {
                    if (!clubMap[p.club]) clubMap[p.club] = { club: p.club, type: '', mc_count: 0, pt_count: 0, total_poin: 0 };
                    clubMap[p.club].pt_count++;
                });
                if (w.RAW.clubSummary) {
                    var csLookup = {}; w.RAW.clubSummary.forEach(function (c) { csLookup[c.club] = c; });
                    Object.keys(clubMap).forEach(function (club) {
                        var existing = csLookup[club];
                        if (existing) {
                            existing.mc_count = clubMap[club].mc_count; existing.pt_count = clubMap[club].pt_count;
                            if (clubMap[club].mc_count > 0) existing.avg_mar = Math.round(clubMap[club].total_poin / clubMap[club].mc_count);
                        }
                    });
                }

                /* â”€â”€ Trigger full re-render â”€â”€ */
                try { if (w.recomp) w.recomp(); } catch (e) { }
                try { if (w.populateDropdowns) w.populateDropdowns(); } catch (e) { }
                try { if (w.renderExec) w.renderExec(); } catch (e) { }
                try { if (w.renderMCKPIs) w.renderMCKPIs(); } catch (e) { }
                try { if (w.renderMCDist) w.renderMCDist(); } catch (e) { }
                try { if (w.renderDiagChart) w.renderDiagChart(); } catch (e) { }
                try { if (w.renderMC) w.renderMC(); } catch (e) { }
                try { if (w.renderPTKPIs) w.renderPTKPIs(); } catch (e) { }
                try { if (w.renderPTDist) w.renderPTDist(); } catch (e) { }
                try { if (w.renderPT) w.renderPT(); } catch (e) { }
                try { if (w.renderClub) w.renderClub(); } catch (e) { }
                try { if (w.renderOverview) w.renderOverview(); } catch (e) { }

                console.log('âœ“ MCPT iframe updated from Google Sheets (4 tabs) â€” MC:' + w.RAW.mcList.length + ' PT:' + w.RAW.ptList.length);
            } catch (e) {
                console.error('MCPT iframe live update error:', e, e.stack);
            }
        }

        /* â•â•â•â• UPLOAD â•â•â•â• */
        window.up = function (t, inp) {
            const f = inp.files[0]; if (!f) return; const r = new FileReader(); r.onload = e => {
                try {
                    const wb = XLSX.read(e.target.result, { type: 'array' });
                    if (t === 'rev') { H.rev = {}; wb.SheetNames.forEach(sn => { const m = matchM(sn); const d = parseRev(wb.Sheets[sn]); if (d.length) H.rev[m] = d; }); uSt(0, f.name, Object.keys(H.rev).length + 'bln Â· ' + Object.values(H.rev).flat().length + 'klub'); }
                    if (t === 'mc') { H.mc = {}; H.pt = {}; wb.SheetNames.forEach(sn => { const m = matchM(sn); const snl = sn.toLowerCase(); if (snl.includes('pt')) { const dpt = parsePT(wb.Sheets[sn]); if (dpt.length) H.pt[m] = dpt; } else { const dmc = parseMC(wb.Sheets[sn]); if (dmc.length) H.mc[m] = dmc; else { const dpt = parsePT(wb.Sheets[sn]); if (dpt.length) H.pt[m] = dpt; } } }); var mcC = Object.values(H.mc).flat().length, ptC = Object.values(H.pt).flat().length; uSt(1, f.name, (mcC ? mcC + 'MC' : '') + (mcC && ptC ? ' Â· ' : '') + (ptC ? ptC + 'PT' : '')); }
                    if (t === 'pt') { H.pt = {}; wb.SheetNames.forEach(sn => { const m = matchM(sn); const d = parsePT(wb.Sheets[sn]); if (d.length) H.pt[m] = d; }); uSt(2, f.name, Object.keys(H.pt).length + 'bln Â· ' + Object.values(H.pt).flat().length + 'PT'); }
                    if (t === 'vis') {
                        const vs = wb.SheetNames.find(n => /visit/i.test(n)); if (vs) VD = VD.concat(XLSX.utils.sheet_to_json(wb.Sheets[vs], { defval: '' }).map(r => ({ date: r['Tanggal'] || '', am: r['Area Manager'] || r['AM'] || '', club: r['Klub'] || r['Club'] || '', area: r['Kategori'] || r['Checklist'] || '', finding: r['Detail'] || r['Temuan'] || '', assignment: r['Penugasan'] || r['Action'] || '' })).filter(r => r.club));
                        const ss = wb.SheetNames.find(n => /staff/i.test(n)); if (ss) SD = SD.concat(XLSX.utils.sheet_to_json(wb.Sheets[ss], { defval: '' }).map(r => ({ club: r['Klub'] || '', name: r['Nama'] || '', role: r['Role'] || '', pros: r['Kelebihan'] || '', cons: r['Kekurangan'] || '', score: pN(r['Score']) })).filter(r => r.name)); vc++;
                    }
                    buildPeriod(); rf();
                } catch (err) { alert('Error: ' + err.message); }
            }; r.readAsArrayBuffer(f); inp.value = '';
        };

