                h += `<div class="rc-filter"><label>Sort:</label><select onchange="window.sortRcCards(this.value)"><option value="ach">Worst Achievement</option><option value="cl">Lowest Closing</option><option value="rn">Lowest Renewal</option><option value="njm">Lowest NJM</option></select></div>`;
