                                    const cnt = clubBitrix.filter(a => a.staff === name).length;
                                    const tcb = clubBitrix.filter(a => a.staff === name && a.code === 'TCB').length;
                                    const tfulb = clubBitrix.filter(a => a.staff === name && a.code === 'TFULB').length;
