                                    masalah: `${clubHiAud.length} temuan audit severity High â€” staff: ${hiStaff.slice(0, 3).join(', ')}.`,
                                    penyebab: `Pelanggaran berat (absensi, keterlambatan besar, perilaku tidak profesional) menunjukkan kendala budaya kerja.`,
                                    solusi: `Tindak lanjut setiap temuan High. Briefing disiplin SOP. Evaluasi individu repeat offender.`
