                const allHiAud = allAud.filter(a => a.sev === 'H');
                const bitrixClubs = [...new Set(allBitrix.map(a => a.club))];

                // Determine #1 priority using Pareto logic
                let blLine1 = '', blLine2 = '', blLine3 = '';
