                // Cross-reference Bitrix offenders with MC closing rate
                const bitrixMCAll = allBitrix.length ? [...new Set(allBitrix.map(a => a.staff))].map(name => {
                    const mc = wMC.find(m => norm(m.name).includes(norm(name)) || norm(name).includes(norm(m.name)));
                    return { name, cnt: allBitrix.filter(a => a.staff === name).length, mc };
                }).sort((a, b) => b.cnt - a.cnt) : [];
                const critBitrixAll = bitrixMCAll.filter(x => x.mc && (x.mc.closingLeadsRate || 0) < 8);

