                    verdictText: function () {
                        const n = new Date(); const cd = Math.max(1, n.getDate() - 1); const dim = new Date(n.getFullYear(), n.getMonth() + 1, 0).getDate();
                        return `Proyeksi akhir bulan = Actual Ã— (${dim}/${cd}). Asumsi: tren harian saat ini berlanjut sampai tgl ${dim}. Klub dengan proyeksi â‰¥95% target = aman.`;
                    },
                    cols: ['Klub', 'AM', 'Actual', 'Projected EOM', 'Ach Proy %'],
                    rowBuilder: c => {
                        const n = new Date(); const cd = Math.max(1, n.getDate() - 1); const dim = new Date(n.getFullYear(), n.getMonth() + 1, 0).getDate();
                        const proj = cd > 0 ? c.actual * (dim / cd) : c.actual;
                        const projAch = c.target ? (proj / c.target * 100) : 0;
                        const cls = projAch >= 95 ? 'ok' : projAch >= 80 ? 'warn' : 'bad';
                        return { cls, cells: [c.name, c.am || 'â€”', { num: c.actual, fmt: 'id' }, { num: proj, fmt: 'id' }, { num: projAch, fmt: 'pct' }] };
                    },
