        window.cpWA = function () { const CL = curCL(), AM = getAM(); let t = `*FTL â€” ${periodLabel()}*\n`; if (CL.length) { const tT = CL.reduce((s, c) => s + c.target, 0), tA = CL.reduce((s, c) => s + c.actual, 0); t += ` Ach: *${FP(tT ? (tA / tT * 100) : 0)}*\nPer AM:\n`; Object.entries(AM).sort((a, b) => b[1].ach - a[1].ach).forEach(([n, d]) => { t += `â€¢ ${n}: ${FP(d.ach)} (${d.n}klub)\n`; }); } navigator.clipboard.writeText(t).then(() => alert('Copied!')).catch(() => alert('Gagal')); };

