        let TOP5 = [{ "nama": "Rian Nurfalah", "club": "FTL - Pamulang", "avgPoin": 18470.5 }, { "nama": "M. Rasul Purnomo", "club": "FTL - Rawamangun", "avgPoin": 18311.3 }, { "nama": "Abdul Azis", "club": "FTL - SCBD", "avgPoin": 18191.2 }, { "nama": "Slamet Riyadi M", "club": "FTL - Mampang", "avgPoin": 18113.5 }, { "nama": "Bagus Sunandar", "club": "FTL - Satrio", "avgPoin": 17457.9 }];
        let NAT_AVG = 7393.9786585365855;
