        let grM = 2, sKey = 'avgPoin', sDir = -1, cKey = 'avgPoin', cDir = -1;
        let fSp = '', fRek = '', fCl = '', fSr = '', fEW = '', pg = 1, kF = null, kFt = null;
        const PER = 50;
