            const clA = H.rev[a] || [], clB = H.rev[b] || [];
            if (!clA.length && !clB.length) { document.getElementById('perResult').innerHTML = '<div style="color:var(--r);text-align:center;padding:12px">Tidak ada data point untuk periode yang dipilih</div>'; return; }

            const lA = MS[a] || a, lB = MS[b] || b;
            const tTA = clA.reduce((s, c) => s + c.target, 0), tAA = clA.reduce((s, c) => s + c.actual, 0), ovA = tTA ? (tAA / tTA * 100) : 0;
            const tTB = clB.reduce((s, c) => s + c.target, 0), tAB = clB.reduce((s, c) => s + c.actual, 0), ovB = tTB ? (tAB / tTB * 100) : 0;
            const njA = clA.reduce((s, c) => s + (c.njA || 0), 0), njB = clB.reduce((s, c) => s + (c.njA || 0), 0);
            const cpA = clA.reduce((s, c) => s + (c.cpA || 0), 0), cpB = clB.reduce((s, c) => s + (c.cpA || 0), 0);
            const ldA = clA.reduce((s, c) => s + (c.clLeads || 0), 0), ldB = clB.reduce((s, c) => s + (c.clLeads || 0), 0);
            const rnVA = clA.filter(c => c.rnA != null), rnVB = clB.filter(c => c.rnA != null);
