                h += `<div style="padding:10px;text-align:center;font-family:var(--mn);font-size:13px;border-top:1px solid var(--brd-light)">${m.fmt(m.vb)} ${diff != null && Math.abs(diff) > 0.01 ? `<span style="font-size:10px;color:${improved ? 'var(--g)' : 'var(--r)'}">${diff > 0 ? 'â–²' : 'â–¼'}${typeof diff === 'number' && Math.abs(diff) < 100 ? Math.abs(diff).toFixed(1) : FR(Math.abs(diff))}</span>` : ''}</div>`;
