        /* â”€â”€ Fetch Google Sheet by tab NAME (not GID) â”€â”€ */
        function _gsFetchByName(sheetId, sheetName) {
            var url = 'https://docs.google.com/spreadsheets/d/' + sheetId + '/gviz/tq?tqx=out:json&sheet=' + encodeURIComponent(sheetName) + '&headers=1&_=' + Date.now();
            return fetch(url).then(function (r) {
                if (!r.ok) throw new Error('HTTP ' + r.status);
                return r.text();
            }).then(function (txt) {
                var m = txt.match(/setResponse\(([\s\S]+)\)\s*;?\s*$/);
                if (!m) m = txt.match(/^\s*\{[\s\S]+\}\s*$/);
                if (!m) throw new Error('Bad response');
                return _parseGvizResp(JSON.parse(m[1] || m[0]));
            }).catch(function (fetchErr) {
                /* Fallback: JSONP for file:// protocol */
                return new Promise(function (resolve, reject) {
                    var cb = '_trxCb_' + sheetName.replace(/\W/g, '') + '_' + Date.now();
                    var timer = setTimeout(function () { delete window[cb]; reject(new Error('Timeout')); }, 15000);
                    window[cb] = function (resp) {
                        clearTimeout(timer); delete window[cb];
                        var sc = document.querySelector('script[data-trxcb="' + cb + '"]'); if (sc) sc.remove();
                        try { resolve(_parseGvizResp(resp)); } catch (e) { reject(e); }
                    };
                    var s = document.createElement('script'); s.setAttribute('data-trxcb', cb);
                    s.src = 'https://docs.google.com/spreadsheets/d/' + sheetId + '/gviz/tq?tqx=out:json;responseHandler:' + cb + '&sheet=' + encodeURIComponent(sheetName) + '&headers=1&_=' + Date.now();
                    s.onerror = function () { clearTimeout(timer); delete window[cb]; reject(new Error('JSONP fail')); };
                    document.head.appendChild(s);
                });
            });
        }

