            var w = rect.width || parseInt(canvas.style.width) || canvas.width || 300;
            var h = rect.height || parseInt(canvas.style.height) || canvas.height || 150;
            canvas.width = w * dpr;
            canvas.height = h * dpr;
            canvas.style.width = w + 'px';
