            el.innerHTML = '<div style="text-align:center;padding:60px;color:var(--txt2)"><div style="font-size:28px;margin-bottom:12px">â³</div><div style="font-size:13px;font-weight:600">Mengambil data transaksi...</div><div style="font-size:10px;margin-top:4px;opacity:0.6">Fetching 7 tabs dari Google Sheets</div></div>';

