            var colors = ['#3B82F6', '#f59e0b', '#22C55E', '#8b5cf6', '#ef4444', '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1'];
            var total = data.reduce(function (s, d) { return s + d.rev; }, 0) || 1;
            var item = data.find(function (d) { return d.cat === cat; });
            if (!item) return;
            var pct = ((item.rev / total) * 100).toFixed(1);

            var oldP = document.getElementById('donutPopup'); if (oldP) oldP.remove();
            var h = '<div style="position:fixed;inset:0;background:rgba(0,0,0,0.5);backdrop-filter:blur(6px);z-index:10000;display:flex;align-items:center;justify-content:center;padding:20px" onclick="if(event.target===this)this.remove()" id="donutPopup">';
