            h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px">';
            var typeLabel = type === 'membership' ? 'ðŸ‹ï¸ Membership' : type === 'product' ? 'ðŸ›ï¸ Product' : 'ðŸ’³ Payment';
            h += '<div><div style="font-size:14px;font-weight:800;color:var(--txt)">' + typeLabel + ': ' + cat + '</div>';
            h += '<div style="font-size:10px;color:var(--txt2)">' + _trxFmtMo(selM) + ' | ' + pct + '% dari total (' + _trxFmtB(item.rev) + ')</div></div>';
            h += '<button onclick="document.getElementById(\'donutPopup\').remove()" style="background:var(--card);border:1px solid var(--bd);border-radius:50%;width:28px;height:28px;font-size:14px;cursor:pointer;color:var(--txt);display:flex;align-items:center;justify-content:center">âœ•</button></div>';

            /* Per-club breakdown for this category */
            var perClub = [];
