                perClub = Object.keys(map).map(function (k) { return { club: k, rev: map[k].rev, cnt: map[k].cnt, extra: 'New: ' + map[k].newCnt + ' | Renew: ' + map[k].renewCnt }; }).sort(function (a, b) { return b.rev - a.rev; });
