        /* â”€â”€ Draw Donut Chart (HiDPI + Clickable) â”€â”€ */
        function _drawTRXDonut(canvasId, legendId, data, type) {
            var canvas = document.getElementById(canvasId);
            var legendEl = document.getElementById(legendId);
            if (!canvas) return;
            var o = _trxHiDPI(canvas); var ctx = o.ctx, W = o.W, H = o.H;

            var colors = ['#3B82F6', '#f59e0b', '#22C55E', '#8b5cf6', '#ef4444', '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1', '#14b8a6', '#e11d48'];
            var total = data.reduce(function (s, d) { return s + d.rev; }, 0) || 1;
            var cx = W / 2, cy = H / 2, R = Math.min(W, H) / 2 - 10, r = R * 0.55;

            /* Store segment angles for click detection */
            var segments = [];
            var startAngle = -Math.PI / 2;
            data.forEach(function (d, i) {
                var angle = (d.rev / total) * Math.PI * 2;
                ctx.beginPath();
                ctx.moveTo(cx + Math.cos(startAngle) * r, cy + Math.sin(startAngle) * r);
                ctx.arc(cx, cy, R, startAngle, startAngle + angle);
                ctx.arc(cx, cy, r, startAngle + angle, startAngle, true);
                ctx.closePath();
                ctx.fillStyle = colors[i % colors.length];
                ctx.fill();
                segments.push({ start: startAngle, end: startAngle + angle, cat: d.cat });
                startAngle += angle;
            });

            /* Center text */
            ctx.fillStyle = '#333'; ctx.font = 'bold 14px system-ui'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.fillText(_trxFmtB(total), cx, cy - 6);
            ctx.font = '8px system-ui'; ctx.fillStyle = 'rgba(128,128,128,0.7)';
            ctx.fillText('Klik untuk detail', cx, cy + 10);

            /* Click handler */
            canvas.style.cursor = 'pointer';
            canvas.onclick = function (e) {
                var rect = canvas.getBoundingClientRect();
                var mx = e.clientX - rect.left - cx;
                var my = e.clientY - rect.top - cy;
                var dist = Math.sqrt(mx * mx + my * my);
                if (dist < r || dist > R) return;/* outside donut ring */
                var angle = Math.atan2(my, mx);
                /* Normalize angle to match our -PI/2 start */
                for (var si = 0; si < segments.length; si++) {
                    var seg = segments[si];
                    /* Normalize angles */
                    var a = angle, s = seg.start, en = seg.end;
                    if (a < s) a += Math.PI * 2;
                    if (en < s) en += Math.PI * 2;
                    if (a >= s && a < en) {
                        _showDonutDetail(type || 'membership', seg.cat, data);
                        return;
                    }
                }
            };

            /* Legend â€” store data in registry to avoid inline JSON in onclick */
            var regKey = (type || 'm') + '_' + (canvas.id || Math.random());
            _trxDonutReg[regKey] = { type: type, data: data };
            if (legendEl) {
                var lg = '';
                data.slice(0, 8).forEach(function (d, i) {
                    var pct = ((d.rev / total) * 100).toFixed(1);
                    var safeCat = d.cat.replace(/'/g, "\\'");
                    lg += '<div style="display:inline-flex;align-items:center;gap:3px;margin:2px 6px 2px 0;cursor:pointer" onclick="_showDonutDetail(\'' + type + '\',\'' + safeCat + '\',_trxDonutReg[\'' + regKey + '\'].data)"><span style="width:8px;height:8px;border-radius:2px;background:' + colors[i % colors.length] + ';flex-shrink:0"></span><span>' + d.cat + ' (' + pct + '%)</span></div>';
                });
                if (data.length > 8) lg += '<span style="color:var(--txt2)">+' + (data.length - 8) + ' lainnya</span>';
                legendEl.innerHTML = lg;
            }
        }

        /* â”€â”€ Draw Daily Revenue Bar Chart (HiDPI + Compare overlay) â”€â”€ */
        function _drawTRXDailyChart(dates, agg, cmpDates, cmpAgg) {
            var canvas = document.getElementById('trxDailyChart');
            if (!canvas || !dates.length) return;
            var o = _trxHiDPI(canvas); var ctx = o.ctx, W = o.W, H = o.H;

            var vals = dates.map(function (d) { return agg[d].rev; });
            var cmpVals = cmpDates ? cmpDates.map(function (d) { return cmpAgg[d].rev; }) : [];
            var allVals = vals.concat(cmpVals);
            var maxV = Math.max.apply(null, allVals) || 1;

            var padL = 50, padR = 10, padT = 10, padB = 30;
            var cW = W - padL - padR, cH = H - padT - padB;
            var maxLen = Math.max(dates.length, cmpDates ? cmpDates.length : 0);
            var barW = Math.max(2, (cW / maxLen) - 2);
            var halfBar = cmpDates ? barW / 2 : barW;

            /* Grid */
            ctx.strokeStyle = 'rgba(128,128,128,0.1)'; ctx.lineWidth = 0.5;
            for (var g = 0; g <= 4; g++) {
                var gy = padT + cH * (1 - g / 4);
                ctx.beginPath(); ctx.moveTo(padL, gy); ctx.lineTo(W - padR, gy); ctx.stroke();
                ctx.fillStyle = 'rgba(128,128,128,0.5)'; ctx.font = '8px system-ui'; ctx.textAlign = 'right';
                ctx.fillText(_trxFmtB(maxV * g / 4), padL - 5, gy + 3);
            }

            /* Primary bars */
            dates.forEach(function (d, i) {
                var x = padL + (i / maxLen) * cW + 1;
                var bH = (vals[i] / maxV) * cH;
                var y = padT + cH - bH;
                var grd = ctx.createLinearGradient(0, y, 0, padT + cH);
                grd.addColorStop(0, 'rgba(14,165,233,0.8)'); grd.addColorStop(1, 'rgba(14,165,233,0.3)');
                ctx.fillStyle = grd;
                ctx.fillRect(x, y, cmpDates ? halfBar - 1 : barW, bH);

                if (i % Math.ceil(maxLen / 15) === 0 || i === dates.length - 1) {
                    ctx.fillStyle = 'rgba(128,128,128,0.6)'; ctx.font = '7px system-ui'; ctx.textAlign = 'center';
                    ctx.fillText(d.substring(8), x + halfBar / 2, padT + cH + 12);
                }
            });

            /* Compare bars (orange, side by side) */
            if (cmpDates && cmpDates.length) {
                cmpDates.forEach(function (d, i) {
                    var x = padL + (i / maxLen) * cW + halfBar + 1;
                    var bH = (cmpVals[i] / maxV) * cH;
                    var y = padT + cH - bH;
                    var grd = ctx.createLinearGradient(0, y, 0, padT + cH);
                    grd.addColorStop(0, 'rgba(245,158,11,0.7)'); grd.addColorStop(1, 'rgba(245,158,11,0.2)');
                    ctx.fillStyle = grd;
                    ctx.fillRect(x, y, halfBar - 1, bH);
                });
                /* Legend */
                ctx.fillStyle = '#3B82F6'; ctx.fillRect(W - 130, 5, 10, 8);
                ctx.fillStyle = 'rgba(128,128,128,0.7)'; ctx.font = '7px system-ui'; ctx.textAlign = 'left';
                ctx.fillText('Range A', W - 116, 12);
                ctx.fillStyle = '#f59e0b'; ctx.fillRect(W - 70, 5, 10, 8);
                ctx.fillStyle = 'rgba(128,128,128,0.7)';
                ctx.fillText('Compare', W - 56, 12);
            }
        }

