        function anFmt(n) { if (n == null || isNaN(n)) return 'â€”'; const v = Math.round(n); if (Math.abs(v) >= 1e6) return (v / 1e6).toFixed(2) + 'M'; if (Math.abs(v) >= 1e3) return (v / 1e3).toFixed(1) + 'K'; return v.toLocaleString('id-ID'); }
