        function anFmtPct(n) { if (n == null || isNaN(n)) return 'â€”'; return n.toFixed(1) + '%'; }
        function anHeatColor(pct) {
            /* Viridis-ish: low=violet, mid=teal, high=yellow-green */
            if (pct <= 0) return 'transparent';
            const t = Math.min(pct / 100, 1);
            const r = Math.round(94 + (255 - 94) * t);
            const g = Math.round(92 + (200 - 92) * t);
            const b = Math.round(230 - 130 * t);
            const a = 0.25 + 0.65 * t;
            return `rgba(${r},${g},${b},${a})`;
        }
